 1751: 	bool roots_ulist_allocated = false;
 1752: 	struct ulist_iterator uiter;
 1753: 	int ret = 0;
 1754: 
 1755: 	ASSERT(ctx->refs == NULL);
 1756: 
 1757: 	ctx->refs = ulist_alloc(GFP_NOFS);
 1758: 	if (!ctx->refs)
 1759: 		return -ENOMEM;
 1760: 
 1761: 	if (!ctx->roots) {
