  323: 	index = btrfs_bg_flags_to_raid_index(block_group->flags);
  324: 	down_write(&found->groups_sem);
  325: 	list_add_tail(&block_group->list, &found->block_groups[index]);
  326: 	up_write(&found->groups_sem);
  327: }
